#!/usr/bin/env bash
# Disk-backed comparative benchmark harness: Nova (--location, WAL-backed
# RingStore) vs Oxigraph (--location, RocksDB-backed) vs QLever (mmap disk
# index, unchanged from the in-memory comparison since QLever has no other
# mode). This is the disk/persistent-storage sibling of run_comparison.sh
# (which compares all three engines in their *pure in-memory* configuration).
#
# Why a separate script rather than a flag on run_comparison.sh: the two
# comparisons measure fundamentally different things (heap-resident-only vs.
# durable-with-WAL/RocksDB-fsync) and mixing them into one script/report would
# make the methodology harder to state unambiguously. Keeping them as two
# scripts/two reports mirrors the "storage-model fairness" discipline already
# documented in README.md for the in-memory comparison.
#
# Methodology:
#   - Nova:      RingStore::open(dir) — every insert() is WAL-logged
#                (fsync-per-write) before being applied in memory.
#   - Oxigraph:  `serve --location <dir>` -> RocksDB-backed (oxigraph's own
#                default/production persistent mode, oxrocksdb-sys via Docker
#                image build).
#   - QLever:    memory-mapped disk index (same as the in-memory comparison
#                script — QLever has no other mode). A warm-up pass ensures
#                the OS page cache holds the working set resident before
#                timed measurements, consistent with run_comparison.sh.
#
# All three engines are loaded with a byte-identical N-Triples dataset and
# queried with byte-identical SPARQL text (reuses the same dataset/query set
# generated by run_comparison.sh / gen_dataset — run that script first, or
# this one will generate its own if missing).
#
# Usage:
#   ./run_comparison_disk.sh [ENTITIES] [ITERS] [WARMUP]
#
# Defaults: ENTITIES=50000 ITERS=30 WARMUP=5
set -euo pipefail

ENTITIES="${1:-50000}"
ITERS="${2:-30}"
WARMUP="${3:-5}"

ROOT="$(cd "$(dirname "${BASH_SOURCE[0]}")/../.." && pwd)"
BENCH_DIR="/tmp/oxigraph-nova-bench"
QLEVER_DIR="/tmp/qlever_bench_disk"
QLEVER_BIN="${QLEVER_BIN_DIR:-/Users/jgentes/Documents/Workspace/qlever/build}"
DATA="$BENCH_DIR/dataset.nt"
QUERIES="$BENCH_DIR/dataset.queries.json"
OUT_DIR="$ROOT/benches/external"
CSV="$OUT_DIR/raw_results_disk.csv"
RESULTS_MD="$OUT_DIR/RESULTS_DISK.md"

NOVA_LOCATION="/tmp/oxigraph-nova-bench/nova_disk_data"
OXIGRAPH_LOCATION_HOST="/tmp/oxigraph-nova-bench/oxigraph_disk_data"

NOVA_PORT=3031
OXIGRAPH_PORT=7880
QLEVER_PORT=7981
QLEVER_READY_URL="http://localhost:$QLEVER_PORT/?query=SELECT%20%3Fs%20WHERE%20%7B%3Fs%20%3Fp%20%3Fo%7D%20LIMIT%201"

NOVA_CPU_LOG="/tmp/nova_disk_cpu_samples.txt"
QLEVER_CPU_LOG="/tmp/qlever_disk_cpu_samples.txt"
OXIGRAPH_CPU_LOG="/tmp/oxigraph_disk_cpu_samples.txt"

mkdir -p "$BENCH_DIR" "$QLEVER_DIR" "$OUT_DIR"
rm -rf "$NOVA_LOCATION" "$OXIGRAPH_LOCATION_HOST"
mkdir -p "$NOVA_LOCATION" "$OXIGRAPH_LOCATION_HOST"

_footprint_str_to_kb() {
  local s="$1"
  python3 -c "
s = '''$s'''.strip()
mult = {'K': 1.0, 'M': 1024.0, 'G': 1024.0 * 1024.0, 'B': 1.0 / 1024.0}
unit = s[-1] if s else ''
try:
    if unit in mult:
        val = float(s[:-1]) * mult[unit]
    else:
        val = float(s) / 1024.0
except ValueError:
    val = 0.0
print(int(val))
"
}

measure_footprint_kb() {
  local pid="$1"
  if command -v vmmap >/dev/null 2>&1; then
    local raw
    raw=$(vmmap -summary "$pid" 2>/dev/null | awk -F: '/^Physical footprint:/ {print $2; exit}' | tr -d ' ')
    if [ -n "$raw" ]; then
      _footprint_str_to_kb "$raw"
      return
    fi
  fi
  ps -o rss= -p "$pid" 2>/dev/null | tr -d ' '
}

echo "=== [1/6] Building Nova binaries (release) ==="
cd "$ROOT"
cargo build --release -p oxigraph-nova-bench --bin gen_dataset -p oxigraph-nova-server --bin nova_serve

echo "=== [2/6] Ensuring dataset exists (N=$ENTITIES entities) ==="
if [ ! -f "$DATA" ] || [ ! -f "$QUERIES" ]; then
  "$ROOT/target/release/gen_dataset" --entities "$ENTITIES" --out "$DATA"
else
  echo "  Reusing existing dataset at $DATA"
fi

echo "=== [3/6] Building QLever index (fresh, disk-comparison instance) ==="
rm -f "$QLEVER_DIR"/bench.* 2>/dev/null || true
QLEVER_LOAD_START=$(date +%s.%N)
( cd "$QLEVER_DIR" && "$QLEVER_BIN/qlever-index" -i bench -f "$DATA" -F nt )
QLEVER_LOAD_END=$(date +%s.%N)
QLEVER_LOAD_S=$(awk -v a="$QLEVER_LOAD_START" -v b="$QLEVER_LOAD_END" 'BEGIN{printf "%.2f", b-a}')

NOVA_PID=""
QLEVER_PID=""
CPU_SAMPLER_PID=""

cleanup() {
  echo "=== Cleaning up servers ==="
  [ -n "$CPU_SAMPLER_PID" ] && kill "$CPU_SAMPLER_PID" 2>/dev/null || true
  [ -n "$NOVA_PID" ] && kill "$NOVA_PID" 2>/dev/null || true
  [ -n "$QLEVER_PID" ] && kill "$QLEVER_PID" 2>/dev/null || true
  docker rm -f oxigraph_bench_disk >/dev/null 2>&1 || true
}
trap cleanup EXIT

echo "=== [4/6] Starting servers (disk-backed configurations) ==="

wait_ready() {
  local url=$1
  local timeout_s="${2:-60}"
  local i
  for (( i=0; i<timeout_s; i++ )); do
    code=$(curl -s -o /dev/null -w "%{http_code}" "$url" || echo "000")
    if [[ "$code" =~ ^(200|400)$ ]]; then return 0; fi
    sleep 1
  done
  echo "Server at $url did not become ready" >&2
  return 1
}

# --- Nova: persistent WAL-backed RingStore via --location ---
# NOTE: Nova's --location --data load path now calls RingStore::bulk_load(),
# which bypasses the WAL entirely and commits via a single atomic snapshot +
# MANIFEST swap (see benches/external/README.md's "Resolved" section) — this
# is now fast (~1.3s for 1.25M triples, measured). The generous readiness
# timeout is kept as a safety margin for much larger datasets, not because
# the load is expected to be slow anymore.

NOVA_LOAD_START=$(date +%s.%N)
"$ROOT/target/release/nova_serve" --location "$NOVA_LOCATION" --data "$DATA" \
  --bind "127.0.0.1:$NOVA_PORT" > /tmp/nova_serve_disk_bench.log 2>&1 &
NOVA_PID=$!
wait_ready "http://127.0.0.1:$NOVA_PORT/sparql" 3600
NOVA_LOAD_END=$(date +%s.%N)
NOVA_LOAD_S=$(awk -v a="$NOVA_LOAD_START" -v b="$NOVA_LOAD_END" 'BEGIN{printf "%.2f", b-a}')

# --- Oxigraph: serve --location <dir> => RocksDB-backed persistent storage ---
OXIGRAPH_LOAD_START=$(date +%s.%N)
docker rm -f oxigraph_bench_disk >/dev/null 2>&1 || true
docker run -d --name oxigraph_bench_disk -p "$OXIGRAPH_PORT:7878" \
  -v "$OXIGRAPH_LOCATION_HOST:/data" oxigraph/oxigraph:latest \
  serve --location /data --bind 0.0.0.0:7878 >/dev/null
wait_ready "http://localhost:$OXIGRAPH_PORT/sparql"
echo "  Bulk-loading dataset into Oxigraph (RocksDB-backed) via HTTP POST..."
curl -s -X POST -T "$DATA" -H "Content-Type: application/n-triples" \
  "http://localhost:$OXIGRAPH_PORT/store?default" -o /dev/null
OXIGRAPH_LOAD_END=$(date +%s.%N)
OXIGRAPH_LOAD_S=$(awk -v a="$OXIGRAPH_LOAD_START" -v b="$OXIGRAPH_LOAD_END" 'BEGIN{printf "%.2f", b-a}')

# --- QLever: memory-mapped disk index (only supported mode; unchanged) ---
( cd "$QLEVER_DIR" && "$QLEVER_BIN/qlever-server" -i bench -p "$QLEVER_PORT" -n > /tmp/qlever_server_disk_bench.log 2>&1 & )
sleep 1
QLEVER_PID=$(pgrep -f "qlever-server -i bench -p $QLEVER_PORT" | head -1)

echo "Waiting for all servers to be ready..."
wait_ready "$QLEVER_READY_URL"

: > "$NOVA_CPU_LOG"
: > "$QLEVER_CPU_LOG"
: > "$OXIGRAPH_CPU_LOG"
(
  while true; do
    ps -o %cpu= -p "$NOVA_PID" 2>/dev/null | tr -d ' ' >> "$NOVA_CPU_LOG" || true
    ps -o %cpu= -p "$QLEVER_PID" 2>/dev/null | tr -d ' ' >> "$QLEVER_CPU_LOG" || true
    docker stats oxigraph_bench_disk --no-stream --format '{{.CPUPerc}}' 2>/dev/null | tr -d '%' >> "$OXIGRAPH_CPU_LOG" || true
    sleep 0.3
  done
) &
CPU_SAMPLER_PID=$!

echo "=== [5/6] Running benchmark queries (warmup=$WARMUP, iters=$ITERS) ==="
echo "engine,query,iter,time_s" > "$CSV"

run_engine_queries() {
  local engine="$1"
  local url="$2"
  local accept_header="$3"

  while IFS=$'\t' read -r name sparql expected; do
    for _ in $(seq 1 "$WARMUP"); do
      curl -s -G --data-urlencode "query=$sparql" -H "$accept_header" "$url" -o /dev/null
    done

    if [ "$expected" != "null" ]; then
      actual=$(curl -s -G --data-urlencode "query=$sparql" -H "$accept_header" "$url" \
        | jq -r '.results.bindings | length' 2>/dev/null || echo "ERROR")
      if [ "$actual" != "$expected" ]; then
        echo "  [WARN] [$engine] $name: expected $expected bindings, got $actual" >&2
      fi
    fi

    for i in $(seq 1 "$ITERS"); do
      t=$(curl -s -G --data-urlencode "query=$sparql" -H "$accept_header" "$url" \
        -o /dev/null -w "%{time_total}")
      echo "$engine,$name,$i,$t" >> "$CSV"
    done
    echo "  [$engine] $name done"
  done < <(jq -r '.[] | [.name, .sparql, (.expected // "null")] | @tsv' "$QUERIES")
}

run_engine_queries "nova"     "http://127.0.0.1:$NOVA_PORT/sparql"    "Accept: application/sparql-results+json"
NOVA_RSS_KB=$(measure_footprint_kb "$NOVA_PID")

run_engine_queries "oxigraph" "http://localhost:$OXIGRAPH_PORT/sparql" "Accept: application/sparql-results+json"
OXIGRAPH_MEM=$(docker stats oxigraph_bench_disk --no-stream --format '{{.MemUsage}}' | awk -F'/' '{print $1}' | tr -d ' ')

run_engine_queries "qlever"   "http://localhost:$QLEVER_PORT/"         "Accept: application/sparql-results+json"
QLEVER_RSS_KB=$(measure_footprint_kb "$QLEVER_PID")

kill "$CPU_SAMPLER_PID" 2>/dev/null || true
CPU_SAMPLER_PID=""

avg_cpu() {
  local log="$1"
  if [ -s "$log" ]; then
    awk '{s+=$1; n++} END { if (n>0) printf "%.2f", s/n; else print "0" }' "$log"
  else
    echo "0"
  fi
}
NOVA_CPU_PCT=$(avg_cpu "$NOVA_CPU_LOG")
QLEVER_CPU_PCT=$(avg_cpu "$QLEVER_CPU_LOG")
OXIGRAPH_CPU_PCT=$(avg_cpu "$OXIGRAPH_CPU_LOG")

echo "=== [6/6] Generating report ==="

NOVA_DISK_KB=$(du -sk "$NOVA_LOCATION" 2>/dev/null | awk '{print $1}')
OXIGRAPH_DISK_KB=$(du -sk "$OXIGRAPH_LOCATION_HOST" 2>/dev/null | awk '{print $1}')
QLEVER_DISK_KB=$(du -sk "$QLEVER_DIR" 2>/dev/null | awk '{print $1}')

echo "Nova mem:      ${NOVA_RSS_KB} KB | avg CPU: ${NOVA_CPU_PCT}% | on-disk: ${NOVA_DISK_KB} KB"
echo "QLever mem:    ${QLEVER_RSS_KB} KB | avg CPU: ${QLEVER_CPU_PCT}% | on-disk: ${QLEVER_DISK_KB} KB"
echo "Oxigraph MEM:  ${OXIGRAPH_MEM} | avg CPU: ${OXIGRAPH_CPU_PCT}% | on-disk: ${OXIGRAPH_DISK_KB} KB"

echo "Nova load:     ${NOVA_LOAD_S}s | Oxigraph load: ${OXIGRAPH_LOAD_S}s | QLever index build: ${QLEVER_LOAD_S}s"

python3 "$OUT_DIR/generate_report_disk.py" \
  --csv "$CSV" \
  --queries "$QUERIES" \
  --nova-rss-kb "$NOVA_RSS_KB" \
  --qlever-rss-kb "$QLEVER_RSS_KB" \
  --oxigraph-mem "$OXIGRAPH_MEM" \
  --nova-cpu-pct "$NOVA_CPU_PCT" \
  --qlever-cpu-pct "$QLEVER_CPU_PCT" \
  --oxigraph-cpu-pct "$OXIGRAPH_CPU_PCT" \
  --nova-load-s "$NOVA_LOAD_S" \
  --qlever-load-s "$QLEVER_LOAD_S" \
  --oxigraph-load-s "$OXIGRAPH_LOAD_S" \
  --nova-disk-kb "${NOVA_DISK_KB:-0}" \
  --oxigraph-disk-kb "${OXIGRAPH_DISK_KB:-0}" \
  --qlever-disk-kb "${QLEVER_DISK_KB:-0}" \
  --entities "$ENTITIES" \
  --triples "$(( ENTITIES * 25 ))" \
  --out "$RESULTS_MD"

echo ""
echo "Done. Results written to $RESULTS_MD (raw data: $CSV)"
